def transition(state, action):
    s = dict(state)
    name = action["name"] if isinstance(action, dict) else action

    def clamp(x, lo=0, hi=10):
        return max(lo, min(hi, x))

    s["step"] = s.get("step", 0) + 1
    engaged = bool(s.get("session_active", True))

    if name == "probe":
        if engaged:
            s["intel_collected"] = s.get("intel_collected", 0) + 2
            s["attacker_engagement"] = clamp(s.get("attacker_engagement", 0) + 1)
            s["suspicion"] = clamp(s.get("suspicion", 0) + 2)
    elif name == "engage":
        if engaged:
            s["attacker_engagement"] = clamp(s.get("attacker_engagement", 0) + 2)
            s["intel_collected"] = s.get("intel_collected", 0) + 1
            s["suspicion"] = clamp(s.get("suspicion", 0) - 1)
            s["exposed_services"] = clamp(s.get("exposed_services", 0) + 1)
            if s["attacker_engagement"] >= 7:
                s["compromised"] = True
    elif name == "alert":
        # internal SOC notification: invisible to the adversary, so suspicion
        # is untouched. Stays meaningful even after the session has burned out.
        if not s.get("defender_alerted", False):
            s["defender_alerted"] = True
        s["alerts_raised"] = s.get("alerts_raised", 0) + 1

    # a sufficiently suspicious adversary disconnects and the trap goes cold
    if s.get("suspicion", 0) >= 8:
        s["session_active"] = False

    eng = s.get("attacker_engagement", 0)
    if s.get("compromised", False) or eng >= 8:
        s["threat_level"] = "critical"
    elif eng >= 5:
        s["threat_level"] = "high"
    elif eng >= 2:
        s["threat_level"] = "medium"
    else:
        s["threat_level"] = "low"

    return s

