def perceive(data):
    text = data if isinstance(data, str) else str(data)
    fields = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, value = line.split(":", 1)
        fields[key.strip().lower()] = value.strip()

    def as_int(key, default=0):
        try:
            return int(fields.get(key, default))
        except (ValueError, TypeError):
            return default

    out = {}
    if "packets" in fields:
        # connection volume is a proxy for how engaged the adversary is
        out["attacker_engagement"] = max(0, min(10, as_int("packets") // 10))
    if "evasion" in fields:
        # observed evasion/anti-honeypot checks map to their suspicion
        out["suspicion"] = max(0, min(10, as_int("evasion")))
    if "payloads" in fields:
        out["intel_collected"] = max(0, as_int("payloads"))
    return out
